#include <bits/stdc++.h>using namespace std;typedef long long ll;ll mod=1e9+7;int child(int node,map<ll,ll>& mp,vector<vector<ll>>& adj){    ll sum=0;    for(auto it:adj[node]){        sum+=1+child(it,mp,adj);    }    return mp[node]=sum;}int main(){    ll t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<vector<ll>> adj(n+1);        for(ll i=1;i<=n;i++){            ll l,r;            cin>>l>>r;            if(l!=0){                adj[i].push_back(l);                adj[i].push_back(r);            }        }        vector<ll> ans(n+1,0);        map<ll,ll> mp;        int num=child(1,mp,adj);        queue<pair<ll,ll>> q;        q.push({1,0});        while(!q.empty()){            ll node=q.front().first;            ll par=q.front().second;            q.pop();            ans[node]=((mp[node])*2+1+ans[par])%mod;            for(auto it:adj[node]){                q.push({it,node});            }        }        for(ll i=1;i<=n;i++){            cout<<ans[i]<<" ";        }        cout<<endl;    }}